// IndexedDB wrapper for offline storage
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbStorage = {
    initialize: async function () {
        await openDb();
        return true;
    },

    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(item);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function (storeName, indexName, value) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(value);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedCount: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const index = tx.objectStore('inspections').index('isSynced');
            const request = index.count(IDBKeyRange.only(false));
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityCheck = {
    isOnline: function () {
        return navigator.onLine;
    },
    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', false));
    }
};

window.cameraHelper = {
    capturePhoto: function (inputElementId) {
        return new Promise((resolve) => {
            const input = document.getElementById(inputElementId);
            if (!input) { resolve(null); return; }
            input.onchange = async (e) => {
                const file = e.target.files[0];
                if (!file) { resolve(null); return; }
                // Resize for mobile - max 1200px wide
                const bitmap = await createImageBitmap(file);
                const maxW = 1200;
                const scale = Math.min(1, maxW / bitmap.width);
                const canvas = document.createElement('canvas');
                canvas.width = bitmap.width * scale;
                canvas.height = bitmap.height * scale;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(bitmap, 0, 0, canvas.width, canvas.height);
                const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
                resolve(dataUrl);
            };
            input.click();
        });
    }
};

using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Text.Json;

namespace SiteInspector.Services;

public class LocalStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        await _js.InvokeAsync<bool>("indexedDbStorage.initialize");
    }

    // Sites
    public async Task SaveSiteAsync(Site site)
    {
        var json = JsonSerializer.Deserialize<object>(JsonSerializer.Serialize(site, JsonOptions));
        await _js.InvokeAsync<bool>("indexedDbStorage.putItem", "sites", json);
    }

    public async Task<List<Site>> GetAllSitesAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "sites");
        return JsonSerializer.Deserialize<List<Site>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeAsync<bool>("indexedDbStorage.deleteItem", "sites", id);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Deserialize<object>(JsonSerializer.Serialize(inspection, JsonOptions));
        await _js.InvokeAsync<bool>("indexedDbStorage.putItem", "inspections", json);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "inspections", id);
        if (result == null || result.Value.ValueKind == JsonValueKind.Null)
            return null;
        return JsonSerializer.Deserialize<Inspection>(result.Value.GetRawText(), JsonOptions);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "inspections");
        return JsonSerializer.Deserialize<List<Inspection>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task<int> GetUnsyncedCountAsync()
    {
        return await _js.InvokeAsync<int>("indexedDbStorage.getUnsyncedCount");
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeAsync<bool>("indexedDbStorage.deleteItem", "inspections", id);
    }
}

using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Net.Http.Json;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly LocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public event Action? OnSyncStatusChanged;
    public bool IsOnline { get; private set; }
    public int PendingSyncCount { get; private set; }
    public bool IsSyncing { get; private set; }
    public string? LastSyncError { get; private set; }

    public SyncService(LocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityCheck.registerOnlineHandler", _dotNetRef);
        IsOnline = await _js.InvokeAsync<bool>("connectivityCheck.isOnline");
        await UpdatePendingCount();

        // Try sync every 30 seconds when online
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnSyncStatusChanged?.Invoke();

        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!IsOnline || IsSyncing) return;

        try
        {
            IsSyncing = true;
            LastSyncError = null;
            OnSyncStatusChanged?.Invoke();

            var inspections = await _storage.GetAllInspectionsAsync();
            var unsynced = inspections.Where(i => !i.IsSynced && i.Status == InspectionStatus.Completed).ToList();

            foreach (var inspection in unsynced)
            {
                try
                {
                    // Attempt to post to server API
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _storage.SaveInspectionAsync(inspection);
                    }
                }
                catch (HttpRequestException)
                {
                    // Server not reachable — will retry later
                    break;
                }
            }
        }
        catch (Exception ex)
        {
            LastSyncError = ex.Message;
        }
        finally
        {
            IsSyncing = false;
            await UpdatePendingCount();
            OnSyncStatusChanged?.Invoke();
        }
    }

    private async Task UpdatePendingCount()
    {
        try
        {
            PendingSyncCount = await _storage.GetUnsyncedCountAsync();
        }
        catch { /* IndexedDB may not be ready yet */ }
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
        _dotNetRef?.Dispose();
    }
}

