using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Text.Json;

namespace SiteInspector.Services;

public class LocalStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        await _js.InvokeAsync<bool>("indexedDbStorage.initialize");
    }

    // Sites
    public async Task SaveSiteAsync(Site site)
    {
        var json = JsonSerializer.Deserialize<object>(JsonSerializer.Serialize(site, JsonOptions));
        await _js.InvokeAsync<bool>("indexedDbStorage.putItem", "sites", json);
    }

    public async Task<List<Site>> GetAllSitesAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "sites");
        return JsonSerializer.Deserialize<List<Site>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeAsync<bool>("indexedDbStorage.deleteItem", "sites", id);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Deserialize<object>(JsonSerializer.Serialize(inspection, JsonOptions));
        await _js.InvokeAsync<bool>("indexedDbStorage.putItem", "inspections", json);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "inspections", id);
        if (result == null || result.Value.ValueKind == JsonValueKind.Null)
            return null;
        return JsonSerializer.Deserialize<Inspection>(result.Value.GetRawText(), JsonOptions);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var result = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "inspections");
        return JsonSerializer.Deserialize<List<Inspection>>(result.GetRawText(), JsonOptions) ?? new();
    }

    public async Task<int> GetUnsyncedCountAsync()
    {
        return await _js.InvokeAsync<int>("indexedDbStorage.getUnsyncedCount");
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeAsync<bool>("indexedDbStorage.deleteItem", "inspections", id);
    }
}

