@page "/site/{SiteId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<div class="page-container">
    @if (_site == null)
    {
        <div class="loading">Loading...</div>
    }
    else
    {
        <div class="page-header">
            <div>
                <a href="/" class="back-link">← Sites</a>
                <h1>@_site.Name</h1>
                <p class="subtitle">@_site.Address</p>
            </div>
            <button class="btn-primary" @onclick="StartNewInspection">+ Inspect</button>
        </div>

        @if (_inspections.Count == 0)
        {
            <div class="empty-state">
                <span class="empty-icon">📋</span>
                <p>No inspections yet for this site.</p>
                <p>Tap <strong>+ Inspect</strong> to start one.</p>
            </div>
        }
        else
        {
            <div class="inspection-list">
                @foreach (var inspection in _inspections.OrderByDescending(i => i.InspectedAt))
                {
                    <div class="inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                        <div class="inspection-info">
                            <div class="inspection-date">@inspection.InspectedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</div>
                            <div class="inspection-meta">
                                @{ var passed = inspection.Checklist.Count(c => c.Result == CheckResult.Pass); }
                                @{ var failed = inspection.Checklist.Count(c => c.Result == CheckResult.Fail); }
                                @{ var total = inspection.Checklist.Count; }
                                <span class="badge badge-pass">✓ @passed</span>
                                <span class="badge badge-fail">✗ @failed</span>
                                <span class="badge badge-total">@total items</span>
                                @if (inspection.Photos.Count > 0)
                                {
                                    <span class="badge badge-photo">📷 @inspection.Photos.Count</span>
                                }
                            </div>
                            @if (!string.IsNullOrWhiteSpace(inspection.InspectorName))
                            {
                                <div class="inspector-name">By @inspection.InspectorName</div>
                            }
                        </div>
                        <div class="inspection-status-col">
                            @if (inspection.Status == InspectionStatus.Completed)
                            {
                                <span class="status-badge completed">Done</span>
                            }
                            else
                            {
                                <span class="status-badge in-progress">Draft</span>
                            }
                            @if (inspection.IsSynced)
                            {
                                <span class="sync-indicator synced">☁️</span>
                            }
                            else
                            {
                                <span class="sync-indicator pending">⏳</span>
                            }
                        </div>
                    </div>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Site? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Storage.GetAllSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        if (_site != null)
        {
            _inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
        }
    }

    private void StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "",
            Checklist = ChecklistTemplates.GetStandardChecklist()
        };

        // Save and navigate - we save async in the background
        _ = Task.Run(async () => await Storage.SaveInspectionAsync(inspection));
        Nav.NavigateTo($"/inspect/{inspection.Id}");
    }

    private void OpenInspection(string id)
    {
        Nav.NavigateTo($"/inspect/{id}");
    }
}

