@page "/inspect/{InspectionId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-container inspection-page">
    @if (_inspection == null)
    {
        <div class="loading">Loading inspection...</div>
    }
    else
    {
        <div class="page-header compact">
            <div>
                <a href="/site/@_inspection.SiteId" class="back-link">← @_inspection.SiteName</a>
                <h1>Safety Inspection</h1>
            </div>
            <div class="header-actions">
                @if (_inspection.Status == InspectionStatus.InProgress)
                {
                    <button class="btn-success" @onclick="CompleteInspection">✓ Complete</button>
                }
            </div>
        </div>

        <!-- Inspector name -->
        <div class="inspector-field">
            <input @bind="_inspection.InspectorName" @bind:event="oninput" @bind:after="SaveDebounced"
                   placeholder="Inspector name" class="input-field" />
        </div>

        <!-- Tab navigation -->
        <div class="tab-bar">
            <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
                Checklist (@_inspection.Checklist.Count)
            </button>
            <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
                Photos (@_inspection.Photos.Count)
            </button>
            <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
                Notes
            </button>
        </div>

        @if (_activeTab == "checklist")
        {
            <div class="checklist-container">
                @foreach (var category in _inspection.Checklist.GroupBy(c => c.Category))
                {
                    <div class="checklist-category">
                        <h3 class="category-title">@category.Key</h3>
                        @foreach (var item in category)
                        {
                            <div class="checklist-item @GetItemClass(item)">
                                <div class="item-description">@item.Description</div>
                                <div class="item-actions">
                                    <button class="check-btn pass @(item.Result == CheckResult.Pass ? "active" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                                    <button class="check-btn fail @(item.Result == CheckResult.Fail ? "active" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                                    <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "active" : "")"
                                            @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                                    <button class="check-btn note @(!string.IsNullOrEmpty(item.Notes) ? "has-note" : "")"
                                            @onclick="() => ToggleItemNote(item)">📝</button>
                                </div>
                                @if (_expandedNoteId == item.Id)
                                {
                                    <div class="item-note-field">
                                        <textarea @bind="item.Notes" @bind:event="oninput" @bind:after="SaveDebounced"
                                                  placeholder="Add note for this item..." rows="2"></textarea>
                                    </div>
                                }
                            </div>
                        }
                    </div>
                }
            </div>

            <!-- Progress bar -->
            <div class="progress-footer">
                @{ var checked_count = _inspection.Checklist.Count(c => c.Result != CheckResult.NotChecked); }
                @{ var total_count = _inspection.Checklist.Count; }
                <div class="progress-bar">
                    <div class="progress-fill" style="width: @(total_count > 0 ? (checked_count * 100 / total_count) : 0)%"></div>
                </div>
                <span class="progress-text">@checked_count / @total_count checked</span>
            </div>
        }
        else if (_activeTab == "photos")
        {
            <div class="photos-container">
                <input type="file" id="photo-capture" accept="image/*" capture="environment" style="display:none" />
                <button class="btn-primary photo-btn" @onclick="CapturePhoto">📷 Take Photo</button>

                @if (_inspection.Photos.Count == 0)
                {
                    <div class="empty-state small">
                        <p>No photos yet. Tap the button above to capture.</p>
                    </div>
                }
                else
                {
                    <div class="photo-grid">
                        @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                        {
                            <div class="photo-card">
                                <img src="@photo.Base64Data" alt="@photo.Caption" class="photo-thumb" />
                                <div class="photo-meta">
                                    <input @bind="photo.Caption" @bind:event="oninput" @bind:after="SaveDebounced"
                                           placeholder="Add caption..." class="photo-caption-input" />
                                    <button class="btn-danger-sm" @onclick="() => RemovePhoto(photo)">🗑️</button>
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>
        }
        else if (_activeTab == "notes")
        {
            <div class="notes-container">
                <textarea @bind="_inspection.Notes" @bind:event="oninput" @bind:after="SaveDebounced"
                          placeholder="General inspection notes, observations, follow-up items..."
                          class="notes-textarea" rows="12"></textarea>
            </div>
