@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private string? _expandedNoteId;
    private CancellationTokenSource? _saveCts;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(InspectionId);
    }

    private void SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = (item.Result == result) ? CheckResult.NotChecked : result;
        _ = SaveAsync();
    }

    private void ToggleItemNote(ChecklistItem item)
    {
        _expandedNoteId = _expandedNoteId == item.Id ? null : item.Id;
    }

    private async Task SaveDebounced()
    {
        _saveCts?.Cancel();
        _saveCts = new CancellationTokenSource();
        var token = _saveCts.Token;

        try
        {
            await Task.Delay(500, token);
            await SaveAsync();
        }
        catch (TaskCanceledException) { }
    }

    private async Task SaveAsync()
    {
        if (_inspection != null)
        {
            await Storage.SaveInspectionAsync(_inspection);
        }
    }

    private async Task CapturePhoto()
    {
        var dataUrl = await JS.InvokeAsync<string?>("cameraHelper.capturePhoto", "photo-capture");
        if (!string.IsNullOrEmpty(dataUrl) && _inspection != null)
        {
            var photo = new PhotoRecord
            {
                FileName = $"photo_{DateTime.Now:yyyyMMdd_HHmmss}.jpg",
                Base64Data = dataUrl
            };
            _inspection.Photos.Add(photo);
            await SaveAsync();
            StateHasChanged();
        }
    }

    private async Task RemovePhoto(PhotoRecord photo)
    {
        if (_inspection != null)
        {
            _inspection.Photos.Remove(photo);
            await SaveAsync();
        }
    }

    private async Task CompleteInspection()
    {
        if (_inspection != null)
        {
            _inspection.Status = InspectionStatus.Completed;
            await SaveAsync();
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        }
    }

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => ""
    };
}

