                    <span class="sync-badge online">✓ Online</span>
                }
            </div>
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

@code {
    protected override void OnInitialized()
    {
        SyncService.OnSyncStatusChanged += StateHasChanged;
    }
}

