    gap: 1rem;
}
.loading-icon { font-size: 3rem; }
.loading-text { color: var(--gray-500); font-size: 1.1rem; }

/* App layout */
.app-layout {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

.app-header {
    background: var(--primary);
    color: white;
    position: sticky;
    top: 0;
    z-index: 100;
    box-shadow: var(--shadow-lg);
}

.header-content {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    max-width: 800px;
    margin: 0 auto;
    width: 100%;
}

.header-brand {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    color: white;
    text-decoration: none;
    font-weight: 700;
    font-size: 1.1rem;
}

.brand-icon { font-size: 1.4rem; }

.sync-badge {
    font-size: 0.75rem;
    padding: 0.25rem 0.5rem;
    border-radius: 999px;
    font-weight: 600;
    white-space: nowrap;
}
.sync-badge.online { background: rgba(255,255,255,0.2); }
.sync-badge.offline { background: var(--warning); color: white; }
.sync-badge.pending { background: rgba(255,255,255,0.3); }
.sync-badge.syncing { background: rgba(255,255,255,0.3); animation: pulse 1s infinite; }

@keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.6; }
}

