    box-shadow: var(--shadow);
    display: flex;
    align-items: center;
    justify-content: space-between;
    cursor: pointer;
    transition: transform 0.1s;
    min-height: 64px;
}
.site-card:active, .inspection-card:active {
    transform: scale(0.98);
}

.site-info h3, .inspection-info h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
}
.site-address {
    color: var(--gray-500);
    font-size: 0.85rem;
    margin: 0.2rem 0 0;
}

.chevron {
    font-size: 1.5rem;
    color: var(--gray-300);
    font-weight: 300;
}

.inspection-date {
    font-weight: 600;
    font-size: 0.9rem;
}
.inspection-meta {
    display: flex;
    gap: 0.4rem;
    flex-wrap: wrap;
    margin-top: 0.3rem;
}
.badge {
    font-size: 0.7rem;
    padding: 0.15rem 0.4rem;
    border-radius: 4px;
    font-weight: 600;
}
.badge-pass { background: #d1fae5; color: #065f46; }
.badge-fail { background: #fee2e2; color: #991b1b; }
.badge-total { background: var(--gray-100); color: var(--gray-700); }
.badge-photo { background: #dbeafe; color: #1e40af; }

.inspector-name {
    font-size: 0.8rem;
    color: var(--gray-500);
    margin-top: 0.2rem;
}

.inspection-status-col {
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    gap: 0.3rem;
}
.status-badge {
    font-size: 0.7rem;
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    font-weight: 600;
}
.status-badge.completed { background: #d1fae5; color: #065f46; }
.status-badge.in-progress { background: #fef3c7; color: #92400e; }
.sync-indicator { font-size: 0.8rem; }

.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: var(--gray-500);
}
.empty-state.small { padding: 2rem 1rem; }
.empty-icon { font-size: 3rem; display: block; margin-bottom: 1rem; }

.inspector-field {
    margin-bottom: 0.75rem;
}

.tab-bar {
    display: flex;
    border-bottom: 2px solid var(--gray-200);
    margin-bottom: 1rem;
    gap: 0;
}
.tab {
    flex: 1;
    padding: 0.75rem 0.5rem;
    border: none;
    background: none;
    font-size: 0.85rem;
    font-weight: 600;
    color: var(--gray-500);
    cursor: pointer;
    border-bottom: 2px solid transparent;
    margin-bottom: -2px;
    min-height: 44px;
}
.tab.active {
    color: var(--primary);
    border-bottom-color: var(--primary);
}

.checklist-container {
    padding-bottom: 4rem;
}
.checklist-category {
    margin-bottom: 1.5rem;
}
.category-title {
    font-size: 0.85rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--gray-500);
    margin: 0 0 0.5rem;
    padding-bottom: 0.3rem;
    border-bottom: 1px solid var(--gray-200);
}

.checklist-item {
    background: white;
    border-radius: var(--radius);
    padding: 0.75rem;
    margin-bottom: 0.4rem;
    box-shadow: var(--shadow);
    transition: border-left 0.15s;
    border-left: 4px solid transparent;
}
.checklist-item.item-pass { border-left-color: var(--success); }
.checklist-item.item-fail { border-left-color: var(--danger); }
.checklist-item.item-na { border-left-color: var(--gray-300); }

.item-description {
    font-size: 0.9rem;
    margin-bottom: 0.5rem;
    line-height: 1.3;
}

.item-actions {
    display: flex;
    gap: 0.4rem;
}

.check-btn {
    min-width: 44px;
    min-height: 44px;
    border-radius: 8px;
    border: 2px solid var(--gray-200);
    background: white;
    font-size: 1.1rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.1s;
}
.check-btn:active { transform: scale(0.92); }
.check-btn.pass.active { background: #d1fae5; border-color: var(--success); }
.check-btn.fail.active { background: #fee2e2; border-color: var(--danger); }
.check-btn.na.active { background: var(--gray-100); border-color: var(--gray-500); }
.check-btn.note.has-note { background: #fef3c7; border-color: var(--warning); }

.item-note-field {
    margin-top: 0.5rem;
}
.item-note-field textarea {
    width: 100%;
    padding: 0.5rem;
    border: 1px solid var(--gray-300);
    border-radius: 8px;
    font-size: 0.9rem;
    resize: vertical;
    font-family: inherit;
}

.progress-footer {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: white;
    padding: 0.75rem 1rem;
    box-shadow: 0 -2px 8px rgba(0,0,0,0.1);
    display: flex;
    align-items: center;
    gap: 0.75rem;
    z-index: 50;
}
.progress-bar {
    flex: 1;
    height: 8px;
    background: var(--gray-200);
    border-radius: 4px;
    overflow: hidden;
}
.progress-fill {
    height: 100%;
    background: var(--success);
    border-radius: 4px;
    transition: width 0.3s ease;
}
.progress-text {
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--gray-500);
    white-space: nowrap;
}

.photos-container {
    padding-bottom: 1rem;
}
.photo-btn {
    width: 100%;
    margin-bottom: 1rem;
    padding: 1rem;
    font-size: 1.1rem;
}
.photo-grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: 0.75rem;
}
.photo-card {
    background: white;
    border-radius: var(--radius);
    overflow: hidden;
    box-shadow: var(--shadow);
}
.photo-thumb {
    width: 100%;
    height: 200px;
    object-fit: cover;
}
.photo-meta {
    padding: 0.75rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}
.photo-caption-input {
    flex: 1;
    border: 1px solid var(--gray-200);
    border-radius: 6px;
    padding: 0.4rem 0.6rem;
    font-size: 0.85rem;
    min-height: 36px;
}
.btn-danger-sm {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 0.3rem;
    min-width: 36px;
    min-height: 36px;
}

.notes-textarea {
    width: 100%;
    padding: 0.75rem;
    border: 1px solid var(--gray-300);
    border-radius: var(--radius);
    font-size: 1rem;
    font-family: inherit;
    resize: vertical;
    min-height: 200px;
}
.notes-textarea:focus {
    outline: none;
    border-color: var(--primary);
}

.loading {
    text-align: center;
    padding: 2rem;
    color: var(--gray-500);
}

#blazor-error-ui {
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}
#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}

.loading-progress {
    width: 60px;
    height: 60px;
}
.loading-progress circle {
    fill: none;
    stroke-width: 3px;
}
.loading-progress circle:first-child {
    stroke: var(--gray-200);
}
.loading-progress circle:last-child {
    stroke: var(--primary);
    stroke-dasharray: 180;
    animation: spin 1s linear infinite;
    transform-origin: center;
}
@keyframes spin {
    to { transform: rotate(360deg); }
}

@media (min-width: 600px) {
    .photo-grid {
        grid-template-columns: 1fr 1fr;
    }
}
CSSEOF

